export default function LunaMemoryProvenance() {
  const [selectedMemory, setSelectedMemory] = useState(null);
  const [view, setView] = useState("timeline"); // timeline | graph | sources
  const [filterType, setFilterType] = useState(null);

  const memories = Object.values(MEMORY_PROVENANCE);
  const allEdges = memories.flatMap(m => 
    (m.edges || []).map(e => ({ from: m.id, ...e }))
  );

  // Timeline sorting
  const timelineSorted = [...memories].sort((a, b) => {
    const aTime = a.sources[0]?.timestamp || "2025-01-01";
    const bTime = b.sources[0]?.timestamp || "2025-01-01";
    return new Date(aTime) - new Date(bTime);
  });

  const selected = memories.find(m => m.id === selectedMemory);

  return (
    <div style={{ display: "flex", height: "100vh", background: "#08080f", color: "#d0d2d8", fontFamily: "'IBM Plex Mono', monospace", fontSize: 12, overflow: "hidden" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=IBM+Plex+Mono:wght@300;400;500;600&display=swap');
        .mem-card { transition: all 0.15s; cursor: pointer; }
        .mem-card:hover { border-color: rgba(255,255,255,0.1) !important; background: rgba(255,255,255,0.02) !important; }
        ::-webkit-scrollbar { width: 4px; }
        ::-webkit-scrollbar-track { background: transparent; }
        ::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.06); border-radius: 2px; }
      `}</style>

      {/* LEFT: Memory List */}
