          <div style={{ fontSize: 10, letterSpacing: 3, color: "#c8ff00", fontWeight: 600, marginBottom: 8 }}>LUNA'S MEMORY</div>
          <div style={{ fontSize: 9, color: "#3a3a50" }}>Full provenance trace · {memories.length} nodes</div>

          {/* Type filter */}
          <div style={{ display: "flex", gap: 3, marginTop: 8, flexWrap: "wrap" }}>
            {Object.entries(MEMORY_TYPES).map(([k, v]) => {
              const count = memories.filter(m => m.type === k).length;
              if (!count) return null;
              return (
                <button key={k} onClick={() => setFilterType(filterType === k ? null : k)}
                  style={{ padding: "2px 6px", borderRadius: 3, border: `1px solid ${filterType === k ? v.color + "40" : "#151520"}`, background: filterType === k ? v.color + "10" : "#0c0c15", color: filterType === k ? v.color : "#4a4a60", fontFamily: "inherit", fontSize: 8, cursor: "pointer" }}>
                  {v.icon} {count}
                </button>
              );
            })}
          </div>
        </div>

        <div style={{ padding: "12px 16px" }}>
          {timelineSorted
            .filter(m => !filterType || m.type === filterType)
            .map(m => {
              const mt = MEMORY_TYPES[m.type];
              const isSelected = selectedMemory === m.id;
              const firstSource = m.sources[0];
              return (
                <div key={m.id} onClick={() => setSelectedMemory(m.id)} className="mem-card"
                  style={{ padding: 10, borderRadius: 6, marginBottom: 6, background: isSelected ? "#1a1a28" : "#0c0c15", border: `1px solid ${isSelected ? mt.color + "40" : "#101018"}` }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 4 }}>
                    <span style={{ fontSize: 11, color: mt.color }}>{mt.icon}</span>
                    <span style={{ fontSize: 8, color: mt.color, letterSpacing: 0.5 }}>{mt.label}</span>
                    {m.emotionalWeight && <span style={{ fontSize: 7, padding: "1px 4px", borderRadius: 2, background: "#f472b610", color: "#f472b6" }}>❤︎ {(m.emotionalWeight * 100).toFixed(0)}%</span>}
                    <div style={{ flex: 1 }} />
                    <span style={{ fontSize: 7, color: "#3a3a50" }}>{(m.confidence * 100).toFixed(0)}%</span>
                  </div>
                  <div style={{ fontSize: 10, color: "#c8cad0", lineHeight: 1.5, marginBottom: 4 }}>{m.content}</div>
                  {firstSource && (
                    <div style={{ fontSize: 8, color: "#3a3a50" }}>
                      {new Date(firstSource.timestamp).toLocaleDateString()} · {firstSource.conversation}
                    </div>
                  )}
                </div>
              );
            })}
        </div>
      </div>

      {/* RIGHT: Detail View */}
      <div style={{ flex: 1, overflow: "auto", padding: 24 }}>
        {!selected ? (
          <div style={{ display: "flex", alignItems: "center", justifyContent: "center", height: "100%", color: "#3a3a50", fontSize: 11 }}>
            Select a memory to view full provenance →
          </div>
        ) : (
          <div>
            {/* Header */}
            <div style={{ marginBottom: 20 }}>
              <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 8 }}>
                <span style={{ fontSize: 18, color: MEMORY_TYPES[selected.type].color }}>{MEMORY_TYPES[selected.type].icon}</span>
