                <div style={{ flex: 1 }} />
                <span style={{ fontSize: 10, padding: "3px 8px", borderRadius: 4, background: "#22c55e10", border: "1px solid #22c55e20", color: "#22c55e" }}>
                  {(selected.confidence * 100).toFixed(0)}% confidence
                </span>
                <span style={{ fontSize: 10, padding: "3px 8px", borderRadius: 4, background: "#a78bfa10", border: "1px solid #a78bfa20", color: "#a78bfa" }}>
                  lock-in: {(selected.lockIn * 100).toFixed(0)}%
                </span>
              </div>
              <div style={{ fontSize: 15, color: "#e8e8f0", fontWeight: 400, lineHeight: 1.6 }}>{selected.content}</div>
            </div>

            {/* Thought Pattern */}
            {selected.thoughtPattern && (
              <div style={{ padding: 12, borderRadius: 8, background: "#a78bfa06", borderLeft: "3px solid #a78bfa30", marginBottom: 16 }}>
                <div style={{ fontSize: 8, letterSpacing: 2, color: "#a78bfa", marginBottom: 4 }}>THOUGHT PATTERN</div>
                <div style={{ fontSize: 11, color: "#9ca3af", lineHeight: 1.6, fontStyle: "italic" }}>{selected.thoughtPattern}</div>
              </div>
            )}

            {/* Feeling */}
            {selected.feeling && (
              <div style={{ padding: 12, borderRadius: 8, background: "#f472b606", borderLeft: "3px solid #f472b630", marginBottom: 16 }}>
                <div style={{ fontSize: 8, letterSpacing: 2, color: "#f472b6", marginBottom: 4 }}>FEELING IN THAT MOMENT</div>
                <div style={{ fontSize: 11, color: "#9ca3af", lineHeight: 1.6 }}>{selected.feeling}</div>
              </div>
            )}

            {/* Sources */}
            <div style={{ marginBottom: 20 }}>
              <div style={{ fontSize: 8, letterSpacing: 2, color: "#3a3a50", marginBottom: 10 }}>SOURCES ({selected.sources.length})</div>
              {selected.sources.map((src, i) => (
                <div key={i} style={{ padding: 14, borderRadius: 8, background: "#0c0c15", border: "1px solid #151520", marginBottom: 8 }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 6 }}>
                    <span style={{ fontSize: 10, color: "#06b6d4" }}>🔗 {src.conversation}</span>
                    <div style={{ flex: 1 }} />
                    <span style={{ fontSize: 8, color: "#3a3a50" }}>
                      {new Date(src.timestamp).toLocaleString()}
                    </span>
                  </div>

                  {src.messageRange && (
                    <div style={{ fontSize: 8, color: "#4a4a60", marginBottom: 4 }}>
                      Messages {src.messageRange[0]}-{src.messageRange[1]}
                    </div>
                  )}

                  <div style={{ fontSize: 9, color: "#eab308", marginBottom: 6 }}>
                    Extracted by: {src.extractedBy}
                  </div>

                  <div style={{ fontSize: 10, color: "#5a5c68", lineHeight: 1.6, marginBottom: 8, fontStyle: "italic" }}>
                    "{src.context}"
                  </div>

                  {src.snippet && (
                    <div style={{ padding: 10, borderRadius: 6, background: "#06060c", border: "1px solid #0e0e18", fontSize: 10, color: "#7a7c86", lineHeight: 1.7, fontFamily: "monospace" }}>
                      {src.snippet}
                    </div>
                  )}

                  {src.transcript && (
                    <div style={{ marginTop: 6, fontSize: 8, color: "#252530" }}>
                      📄 {src.transcript}
                    </div>
                  )}
                </div>
              ))}
            </div>

            {/* Edges */}
            {selected.edges && selected.edges.length > 0 && (
              <div>
                <div style={{ fontSize: 8, letterSpacing: 2, color: "#3a3a50", marginBottom: 10 }}>
                  CONNECTIONS ({selected.edges.length})
                </div>
                <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
                  {selected.edges.map((edge, i) => {
                    const targetMem = memories.find(m => m.id === edge.to);
                    const edgeType = EDGE_TYPES[edge.type];
                    if (!targetMem) return null;
                    return (
                      <div key={i} onClick={() => setSelectedMemory(edge.to)} className="mem-card"
                        style={{ display: "flex", alignItems: "center", gap: 10, padding: "8px 10px", borderRadius: 6, background: "#0c0c15", border: "1px solid #101018" }}>
                        <div style={{ width: 80, fontSize: 8, color: edgeType.color, letterSpacing: 0.5 }}>
                          {edgeType.label}
                        </div>
                        <div style={{ width: 2, height: 20, background: `${edgeType.color}30` }} />
                        <div style={{ flex: 1 }}>
                          <div style={{ fontSize: 9, color: "#9ca3af", lineHeight: 1.5 }}>{targetMem.content}</div>
                        </div>
                        <div style={{ fontSize: 8, color: "#3a3a50" }}>
                          {(edge.strength * 100).toFixed(0)}%
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}
